import React, { useState } from 'react';
import {
  Box,
  Paper,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TablePagination,
  TableRow,
  Typography,
  Chip,
  IconButton,
  Collapse,
  Stack,
  Tooltip,
  Divider,
  useTheme,
  alpha,
  Card,
} from '@mui/material';
import _ from 'lodash';

// Icons
import {
  Launch as LaunchIcon,
  KeyboardArrowDown as KeyboardArrowDownIcon,
  KeyboardArrowUp as KeyboardArrowUpIcon,
  Description as DescriptionIcon,
  AccountBalance as AccountBalanceIcon,
  Paid as PaidIcon,
  Person as PersonIcon,
} from '@mui/icons-material';

// สถานะการชำระเงิน (เพิ่มตามความเหมาะสม)
const paymentStatusMap = {
  pending: { label: 'รอดำเนินการ', color: 'warning' },
  approved: { label: 'อนุมัติแล้ว', color: 'success' },
  rejected: { label: 'ปฏิเสธ', color: 'error' },
  paid: { label: 'จ่ายแล้ว', color: 'info' },
  draft: { label: 'แบบร่าง', color: 'default' },
};

// Row component แสดงรายการเบิกจ่าย
function PaymentRow({ payment, handleOnclickDetail }) {
  const [open, setOpen] = useState(false);
  const theme = useTheme();

  // สมมติค่า status (ให้เปลี่ยนตามค่าจริงในข้อมูล)
  const status = payment?.status || 'pending';

  // คำนวณสถานะการแสดงผล
  const statusConfig = paymentStatusMap[status] || paymentStatusMap.pending;

  // Format currency
  const formatCurrency = (amount) => {
    return new Intl.NumberFormat('th-TH', {
      style: 'currency',
      currency: 'THB',
      minimumFractionDigits: 2,
    }).format(amount);
  };

  return (
    <>
      <TableRow
        hover
        sx={{
          '&:nth-of-type(odd)': {
            bgcolor: alpha(theme.palette.primary.main, 0.02),
          },
          cursor: 'pointer',
          '&:hover': {
            bgcolor: alpha(theme.palette.primary.main, 0.05),
          },
          height: 60,
        }}
      >
        {/* หมายเลขเอกสาร */}
        <TableCell onClick={() => handleOnclickDetail(payment._id)}>
          <Typography variant="body2" fontWeight={500} color="primary.main">
            {payment?.payment_number || '-'}
          </Typography>
        </TableCell>

        {/* ประเภทการจ่ายเงิน */}
        <TableCell onClick={() => handleOnclickDetail(payment._id)}>
          <Chip
            size="small"
            label={payment?.pay_type?.name || '-'}
            sx={{
              bgcolor: alpha(theme.palette.secondary.main, 0.1),
              color: 'secondary.main',
              fontWeight: 500,
              fontSize: '0.75rem',
            }}
          />
        </TableCell>

        {/* ผู้ขอเบิก */}
        <TableCell onClick={() => handleOnclickDetail(payment._id)}>
          <Stack direction="row" spacing={1} alignItems="center">
            <PersonIcon fontSize="small" color="action" sx={{ opacity: 0.6 }} />
            <Typography variant="body2">
              {payment?.requester?.firstname} {payment?.requester?.lastname}
            </Typography>
          </Stack>
        </TableCell>

        {/* ผู้รับเงิน */}
        <TableCell onClick={() => handleOnclickDetail(payment._id)}>
          <Typography variant="body2">{payment?.payee?.name || '-'}</Typography>
        </TableCell>

        {/* รายละเอียดคำสั่ง - แสดงปุ่มเพื่อขยายดูรายละเอียดเพิ่มเติม */}
        <TableCell>
          <Stack
            direction="row"
            spacing={1}
            alignItems="center"
            justifyContent="space-between"
          >
            <Typography variant="body2" noWrap sx={{ maxWidth: 150 }}>
              {payment?.expenses_list?.length > 0
                ? `${payment?.expenses_list.length} รายการ`
                : '-'}
            </Typography>
            <IconButton
              aria-label="expand row"
              size="small"
              onClick={() => setOpen(!open)}
            >
              {open ? <KeyboardArrowUpIcon /> : <KeyboardArrowDownIcon />}
            </IconButton>
          </Stack>
        </TableCell>

        {/* ยอดรวม */}
        <TableCell onClick={() => handleOnclickDetail(payment._id)}>
          <Typography variant="body2" fontWeight={600}>
            {formatCurrency(payment?.grand_total || 0)}
          </Typography>
        </TableCell>

        {/* สถานะ */}
        <TableCell onClick={() => handleOnclickDetail(payment._id)}>
          <Chip
            size="small"
            label={statusConfig.label}
            color={statusConfig.color}
            sx={{ fontWeight: 500 }}
          />
        </TableCell>

        {/* Actions */}
        <TableCell align="right">
          <Tooltip title="ดูรายละเอียด">
            <IconButton
              size="small"
              color="primary"
              onClick={() => handleOnclickDetail(payment._id)}
            >
              <LaunchIcon fontSize="small" />
            </IconButton>
          </Tooltip>
        </TableCell>
      </TableRow>

      {/* Collapsible section สำหรับแสดงรายละเอียดเพิ่มเติม */}
      <TableRow>
        <TableCell style={{ paddingBottom: 0, paddingTop: 0 }} colSpan={9}>
          <Collapse in={open} timeout="auto" unmountOnExit>
            <Box
              sx={{
                py: 2,
                px: 3,
                bgcolor: alpha(theme.palette.background.default, 0.7),
              }}
            >
              <Typography
                variant="subtitle2"
                gutterBottom
                color="text.secondary"
              >
                รายการเบิกจ่าย
              </Typography>

              <Stack spacing={1.5} sx={{ mt: 1 }}>
                {payment?.expenses_list?.map((item, index) => (
                  <Card
                    key={index}
                    variant="outlined"
                    sx={{
                      p: 1.5,
                      borderRadius: 1,
                      bgcolor: 'white',
                    }}
                  >
                    <Stack
                      direction={{ xs: 'column', md: 'row' }}
                      spacing={2}
                      justifyContent="space-between"
                    >
                      <Box>
                        <Typography variant="subtitle2" color="primary">
                          {item?.name || 'รายการเบิกจ่าย'}
                        </Typography>

                        <Stack direction="row" spacing={3} sx={{ mt: 1 }}>
                          {item?.budget && (
                            <Stack
                              direction="row"
                              spacing={1}
                              alignItems="center"
                            >
                              <AccountBalanceIcon
                                fontSize="small"
                                color="action"
                                sx={{ opacity: 0.6 }}
                              />
                              <Typography
                                variant="caption"
                                color="text.secondary"
                              >
                                งบประมาณ: {item?.budget?.prefix}{' '}
                                {item?.budget?.budget_number}
                              </Typography>
                            </Stack>
                          )}

                          {item?.project && (
                            <Stack
                              direction="row"
                              spacing={1}
                              alignItems="center"
                            >
                              <DescriptionIcon
                                fontSize="small"
                                color="action"
                                sx={{ opacity: 0.6 }}
                              />
                              <Typography
                                variant="caption"
                                color="text.secondary"
                              >
                                โครงการ: {item?.project?.project_number}
                              </Typography>
                            </Stack>
                          )}
                        </Stack>
                      </Box>

                      <Box>
                        {item?.amount && (
                          <Stack
                            direction="row"
                            spacing={1}
                            alignItems="center"
                          >
                            <PaidIcon fontSize="small" color="primary" />
                            <Typography variant="subtitle2" fontWeight={600}>
                              {formatCurrency(item?.amount)}
                            </Typography>
                          </Stack>
                        )}
                      </Box>
                    </Stack>
                  </Card>
                ))}
              </Stack>
            </Box>
          </Collapse>
        </TableCell>
      </TableRow>
    </>
  );
}

export default function PaymentListTable({
  payments,
  handleOnclickDetail,
  page,
  setPage,
  size,
  setSize,
}) {
  const theme = useTheme();

  const handleChangePage = (event, newPage) => {
    setPage(newPage + 1);
  };

  const handleChangeRowsPerPage = (event) => {
    setSize(parseInt(event.target.value, 10));
    setPage(1);
  };

  return (
    <Card elevation={0} variant="outlined">
      <TableContainer>
        <Table size="medium" aria-label="payment list table">
          <TableHead>
            <TableRow
              sx={{
                bgcolor: theme.palette.primary.main,
              }}
            >
              <TableCell>
                <Typography variant="subtitle2" fontWeight={600} color="white">
                  เลขที่เอกสาร
                </Typography>
              </TableCell>
              <TableCell>
                <Typography variant="subtitle2" fontWeight={600} color="white">
                  ประเภท
                </Typography>
              </TableCell>
              <TableCell>
                <Typography variant="subtitle2" fontWeight={600} color="white">
                  ผู้ขอเบิก
                </Typography>
              </TableCell>
              <TableCell>
                <Typography variant="subtitle2" fontWeight={600} color="white">
                  ผู้รับเงิน
                </Typography>
              </TableCell>
              <TableCell>
                <Typography variant="subtitle2" fontWeight={600} color="white">
                  รายการ
                </Typography>
              </TableCell>
              <TableCell>
                <Typography variant="subtitle2" fontWeight={600} color="white">
                  ยอดรวม
                </Typography>
              </TableCell>
              <TableCell>
                <Typography variant="subtitle2" fontWeight={600} color="white">
                  สถานะ
                </Typography>
              </TableCell>
              <TableCell align="right">
                <Typography variant="subtitle2" fontWeight={600} color="white">
                  จัดการ
                </Typography>
              </TableCell>
            </TableRow>
          </TableHead>

          <TableBody>
            {_.isEmpty(payments?.rows) ? (
              <TableRow>
                <TableCell colSpan={9} align="center" sx={{ py: 4 }}>
                  <Box sx={{ textAlign: 'center' }}>
                    <Typography variant="body1" color="text.secondary">
                      ไม่พบข้อมูลรายการเบิกจ่าย
                    </Typography>
                    <Typography
                      variant="body2"
                      color="text.secondary"
                      sx={{ mt: 0.5 }}
                    >
                      ยังไม่มีรายการเบิกจ่ายในระบบ
                    </Typography>
                  </Box>
                </TableCell>
              </TableRow>
            ) : (
              _.map(payments?.rows, (payment) => (
                <PaymentRow
                  key={payment._id}
                  payment={payment}
                  handleOnclickDetail={handleOnclickDetail}
                />
              ))
            )}
          </TableBody>
        </Table>
      </TableContainer>

      <Divider />

      <TablePagination
        rowsPerPageOptions={[5, 10, 25, 50, 100]}
        component="div"
        count={payments?.total || 0}
        rowsPerPage={size}
        page={page - 1}
        onPageChange={handleChangePage}
        onRowsPerPageChange={handleChangeRowsPerPage}
        labelRowsPerPage="แสดง"
        labelDisplayedRows={({ from, to, count }) =>
          `${from}-${to} จาก ${count !== -1 ? count : `มากกว่า ${to}`}`
        }
      />
    </Card>
  );
}
